/* ══════════════════════════════════════════════════════════
   SHARED UI PRIMITIVES
══════════════════════════════════════════════════════════ */
const Pill = ({children,color=C.orange,style={}}) => (
  <span style={{background:`${color}20`,color,border:`1px solid ${color}35`,
    padding:"2px 10px",borderRadius:4,fontSize:10,fontWeight:700,
    letterSpacing:"0.1em",display:"inline-block",...style}}>{children}</span>
);

const Btn = ({children,variant="primary",onClick,disabled,loading,style={},full}) => {
  const [hov,setHov] = useState(false);
  const v = {
    primary:{background:disabled?`${C.orange}40`:hov?C.orangeD:C.orange,color:"#000",border:"none"},
    ghost:  {background:hov?`${C.border}80`:"transparent",color:C.textSub,border:`1px solid ${C.border}`},
    danger: {background:hov?`${C.red}28`:`${C.red}18`,color:C.red,border:`1px solid ${C.red}35`},
    success:{background:hov?`${C.green}28`:`${C.green}18`,color:C.green,border:`1px solid ${C.green}35`},
    outline:{background:"transparent",color:C.orange,border:`2px solid ${C.orange}`},
    purple: {background:hov?C.purpleL:C.purple,color:"#fff",border:"none"},
    google: {background:hov?"#f5f5f5":"#fff",color:"#1a1a1a",border:`1px solid #e0e0e0`},
  };
  return (
    <button onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      onClick={!disabled&&!loading?onClick:undefined} disabled={disabled||loading}
      style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,
        padding:"9px 18px",borderRadius:7,fontSize:13,fontWeight:700,letterSpacing:"0.02em",
        cursor:disabled||loading?"not-allowed":"pointer",transition:"all 0.18s",
        opacity:disabled?0.45:1,width:full?"100%":undefined,...v[variant],...style}}>
      {loading?<span style={{animation:"spin 0.8s linear infinite",display:"inline-block"}}>◌</span>:children}
    </button>
  );
};

const Card = ({children,style={},glow,onClick}) => {
  const [hov,setHov] = useState(false);
  return (
    <div onClick={onClick}
      onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
      style={{background:C.card,border:`1px solid ${hov&&onClick?C.border2:C.border}`,
        borderRadius:12,padding:20,transition:"all 0.2s",
        cursor:onClick?"pointer":undefined,
        boxShadow:glow?`0 0 24px ${C.orange}18`:hov&&onClick?"0 8px 32px rgba(0,0,0,0.5)":"none",
        ...style}}>{children}</div>
  );
};

const Input = ({value,onChange,placeholder,type="text",style={}}) => (
  <input value={value} onChange={onChange} type={type} placeholder={placeholder}
    style={{width:"100%",background:`${C.surface}`,border:`1px solid ${C.border}`,
      borderRadius:7,padding:"10px 14px",color:C.text,fontSize:13,
      outline:"none",transition:"border-color 0.18s",boxSizing:"border-box",...style}}
    onFocus={e=>e.target.style.borderColor=C.orange}
    onBlur={e=>e.target.style.borderColor=C.border} />
);

const StatusBadge = ({status}) => {
  const m={OPEN:[C.blue],DIAGNOSIS:[C.yellow],ESTIMATE:["#a855f7"],
    APPROVAL:[C.yellow],REPAIR:[C.orange],READY:[C.green],INVOICED:[C.textSub]};
  const [color]=m[status]||[C.textSub];
  return <Pill color={color}>{status}</Pill>;
};

const ProgressBar = ({value,max,color=C.orange,height=4,animate=true}) => (
  <div style={{background:C.border,borderRadius:99,height,overflow:"hidden"}}>
    <div style={{width:`${Math.min((value/max)*100,100)}%`,height:"100%",borderRadius:99,
      background:color,transition:animate?"width 0.5s ease":"none"}} />
  </div>
);

const GlowDivider = ({color=C.orange}) => (
  <div style={{height:1,background:`linear-gradient(90deg,transparent,${color}60,transparent)`,margin:"4px 0"}} />
);

